3	type Item = { type: string; cursed?: boolean; enchantment?: number };
4	
5	type Step = { op: string; items: Item[] };
6	
7	type Customer = { yearsWithMHPCO: number };
8	
9	type Scenario = {
10	  customer: Customer;
11	  steps: Step[];
12	};
13	
14	type StepResult = { premium: number };
15	
16	type ScenarioResult = {
17	  results: StepResult[];
18	};
19	
20	const BASE_PREMIUMS: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	  moonstone: 25,
27	};
28	
29	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
30	const PROCESSING_FEE = 5;
31	
32	const BLOCK_SIZE = 3;
33	const BLOCK_BASE_PREMIUM = 60;
34	
35	const CURSE_SURCHARGE_RATE = 0.5;
36	
37	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
38	const ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
39	
40	const LOYALTY_DISCOUNT_RATE = 0.2;
41	const LOYALTY_DISCOUNT_THRESHOLD_YEARS = 2;
42	
43	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
44	
45	const countItemsByType = (items: Item[]): Map<string, number> => {
46	  const counts = new Map<string, number>();
47	  for (const item of items) {
48	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
49	  }
50	  return counts;
51	};
52	
53	const basePremiumForGroup = (type: string, count: number): number =>
54	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];
55	
56	const calculateTotalBasePremium = (items: Item[]): number =>
57	  [...countItemsByType(items)].reduce(
58	    (total, [type, count]) => total + basePremiumForGroup(type, count),
59	    0,
60	  );
61	
62	const curseSurchargeForItem = (item: Item): number =>
63	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
64	
65	const enchantmentSurchargeForItem = (item: Item): number =>
66	  (item.enchantment ?? 0) >= ENCHANTMENT_SURCHARGE_THRESHOLD
67	    ? BASE_PREMIUMS[item.type] * ENCHANTMENT_SURCHARGE_RATE
68	    : 0;
69	
70	const sumSurcharges = (
71	  items: Item[],
72	  surchargeForItem: (item: Item) => number,
73	): number =>
74	  items.reduce((total, item) => total + surchargeForItem(item), 0);
75	
76	const quoteStep = (
77	  step: Step,
78	  customer: Customer,
79	  stepIndex: number,
80	): StepResult => {
81	  const totalBasePremium = calculateTotalBasePremium(step.items);
82	  const firstInsuranceSurcharge =
83	    totalBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
84	  const curseSurcharge = sumSurcharges(step.items, curseSurchargeForItem);
85	  const enchantmentSurcharge = sumSurcharges(
86	    step.items,
87	    enchantmentSurchargeForItem,
88	  );
89	  const loyaltyDiscount =
90	    customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS
91	      ? totalBasePremium * LOYALTY_DISCOUNT_RATE
92	      : 0;
93	  const followUpDiscount =
94	    stepIndex > 0 ? totalBasePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
95	  return {
96	    premium: Math.ceil(
97	      totalBasePremium + curseSurcharge + enchantmentSurcharge +
98	        firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount +
99	        PROCESSING_FEE,
100	    ),
101	  };
102	};
103	
104	export const processScenario = (scenario: Scenario): ScenarioResult => ({
105	  results: scenario.steps.map((step, index) =>
106	    quoteStep(step, scenario.customer, index),
107	  ),
108	});
