const loyaltyDiscountRate =
  customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS
    ? LOYALTY_DISCOUNT_RATE
    : 0;
const followUpDiscountRate = stepIndex > 0 ? FOLLOW_UP_DISCOUNT_RATE : 0;
const discount =
  totalBasePremium * (loyaltyDiscountRate + followUpDiscountRate);
return {
  premium: Math.ceil(
    totalBasePremium + curseSurcharge + enchantmentSurcharge +
      firstInsuranceSurcharge - discount + PROCESSING_FEE,
  ),
};
